const activeKey = ref('home')

const topMenus: NavItem[] = [
  { key: 'home', label: '首页', icon: icons.home, path: '/homePage/index' },
  { key: 'news', label: '资讯', icon: icons.news, path: '/homePage/news' },
  { key: 'download', label: '下载', icon: icons.download },
  { key: 'study', label: '学习', icon: icons.study },
  { key: 'dynamic', label: '动态', icon: icons.dynamic, path: '/homePage/shares' }
]

const bottomMenus: NavItem[] = [
  // { key: 'sub', label: '订阅', icon: icons.sub },
  { key: 'follow', label: '关注', icon: icons.follow, dot: true,path: '/homePage/focus' },
  { key: 'collect', label: '收藏', icon: icons.collect, path: '/personal/myCollect' },
  { key: 'history', label: '历史', icon: icons.history, path: '/personal/myBrowse' },
  { key: 'vip', label: '会员中心', icon: icons.vip, path: '/vipCenter' },
  { key: 'create', label: '创作中心', icon: icons.create, path: '/creatorCenter' }
]

function handleClick(item: NavItem) {
  activeKey.value = item.key
  console.log('当前点击：', item.label)
  if (userInfoStore.userId == 0 && bottomMenus.includes(item)) {
    ElMessage.warning('请先登录')
    router.push('/login')
    return
  }
  // 点击后设置当前选中的标签
  whichTagStore.setWhichTag(item.key)
 
  if (item.path) {
    router.push(item.path)
  }
}

// 加载选中导航
function loadActiveNav() {
  router.currentRoute.value.path.split('/').forEach(segment => {
    topMenus.concat(bottomMenus).forEach(item => {
      if (item.path && item.path.includes(segment)) {
        activeKey.value = item.key
        useWhichTagStore().setWhichTag(item.key)
      }
    })
  })
}

/**
 * 跳转至AI页面
 */
function handleJumpToAi() {
  if (userInfoStore.userId == 0) {
    ElMessage.warning('请先登录')
    router.push('/login')
    return
  }
  activeKey.value = 'ai'
  whichTagStore.setWhichTag('ai')
  window.open('/ai', '_blank')
}



watch(() => whichTagStore.whichTag, (newVal) => {
  activeKey.value = newVal
})

onMounted(() => {
  loadActiveNav();
});
</script>

